const payload = $input.first().json;
const item = payload.body || payload;

// Telegram sniffer sends flat structure
const textBody = item.text || '';
const isJunk = textBody.length < 20;

// Contact is t.me/username link
const sc = item.from || item.sender_contact || item.contact || 'No disponible';
const sourceChatId = item.chatId || '';

return {
  ...item,
  platform: 'telegram',
  sender_contact: sc,
  final_contact: sc,
  from_name: item.pushName || '',
  chat_name: '',
  source_chat_id: sourceChatId,
  is_group_source: true,
  texto_limpio: textBody.trim(),
  looksValuable: !isJunk,
  message_type: 'text',
  channel_id: ''
};

const results = [];

const HARD_BLOCK = [
  "crypto", "binance", "forex", "casino", "stake", "usdt", "bitcoin", "cripto",
  "wallet", "metamask", "trading", "faucet", "investment", "investir", "invertir",
  "ganar dinero", "ganancias extras", "income online", "work from home",
  "dropshipping", "loan", "prestamo", "préstamo", "credit", "credito", "crédito",
  "paypal", "skrill", "bank transfer", "western union", "click here", "dm now",
  "amazon seller", "shopify", "ecommerce", "airdrop", "nft", "token", "broker", "инди", "контент", "koнтент", "предоплаты", "без предоплаты", "онлифанс", "onlyfans", "вирт", "кружочк", "сигны", "госпожа", "раб", "индивидуалка"
];

const SOFT_BLOCK = [
  "clases", "clase", "teacher", "professor", "university", "course", "curso",
  "seguro", "insurance", "visa", "bank", "banco", "cuenta bancaria", "account",
  "online", "virtual", "customer service", "call center", "marketing job",
  "data entry", "assistant", "agente inmobiliario", "real estate", "cleaning job"
];

const POSITIVE = [
  "apartamento", "apartments", "apartment", "flat", "room", "rooms",
  "plaza", "plazas", "spot", "spots", "agency", "agencia", "club",
  "booking", "tour", "girls", "models", "modelos", "independent",
  "independiente", "trabajo", "vacante", "vacantes",
  "madrid", "barcelona", "valencia", "ibiza", "malaga", "lisboa", "porto",
  "berlin", "munich", "frankfurt", "amsterdam", "zurich", "geneva",
  "milan", "roma", "paris", "hamburg", "санкт", "москва", "питер", "девочки", "девушки", "море", "европу", "модель", "встречи", "встреч", "кастинг", "эскорт", "заработок", "тусовки", "выезд", "апартаменты"
];

function norm(v) {
  return String(v || "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
}

for (const item of $input.all()) {
  const data = item.json;
  const text = norm(data.texto_limpio || "");

  let rejectReason = null;

  const hardHits = HARD_BLOCK.filter(k => text.includes(k)).length;
  const softHits = SOFT_BLOCK.filter(k => text.includes(k)).length;
  const positiveHits = POSITIVE.filter(k => text.includes(k)).length;

  const links = (text.match(/https?:\/\/|wa\.me\/|t\.me\/|telegram/gi) || []).length;
  const tooShort = text.trim().length < 40;

  if (hardHits >= 1) rejectReason = "hard_keyword";
  else if (tooShort && positiveHits === 0) rejectReason = "too_short";
  else if (softHits >= 2 && positiveHits === 0) rejectReason = "context_spam";
  else if (links >= 6 && positiveHits === 0) rejectReason = "link_spam";
  else if (positiveHits === 0 && text.length < 160) rejectReason = "weak_signal";

  results.push({ json: { ...data, looksValuable: !rejectReason, reject_reason: rejectReason } });
}

return results;

const results = [];
const store = $getWorkflowStaticData('global');
if (!store.history) store.history = [];
if (!store.lastSenders) store.lastSenders = {};

const now = Date.now();
const TTL = 86400000;
const BURST_WINDOW = 120000;

store.history = store.history.filter(h => now - h.time < TTL);

function getFingerprint(text) {
  return String(text || "").toLowerCase().replace(/[^a-z0-9]/g, "").substring(0, 100);
}

for (const item of $input.all()) {
  const data = item.json;
  const sender = String(data.final_contact || data.sender_contact || "").replace(/\s/g, '');
  const fp = getFingerprint(data.texto_limpio);

  let isDuplicate = false;

  if (sender && store.lastSenders[sender] && (now - store.lastSenders[sender].time < BURST_WINDOW)) {
    isDuplicate = true;
  }

  if (!isDuplicate) {
    isDuplicate = store.history.some(h => h.fp === fp);
  }

  if (!isDuplicate) {
    store.history.push({ time: now, sender, fp });
    if (sender) store.lastSenders[sender] = { time: now };
    results.push(item);
  }
}

return results;

try {
  const input = $input.first().json;
  const meta = $("Extract Metadata1").first().json;

  let rawText = input.text || input.output || input.result || input.response?.text || input.response || input.data?.text || input.data?.content || input.output?.content || input.content || input.choices?.[0]?.message?.content || "";

  if (!rawText && typeof input === 'object') {
    const deepSearch = JSON.stringify(input);
    const match = deepSearch.match(/"content":"([^"]+)"/);
    if (match) rawText = match[1];
  }

  let cleaned = rawText.replace(/```json/g, '').replace(/```/g, '').trim();
  let jsonMatch = cleaned.match(/\{[\s\S]*\}/);

  if (jsonMatch) {
    jsonMatch[0] = jsonMatch[0].replace(/\n/g, ' ').replace(/\r/g, ' ');
  }

  let jsonStr = jsonMatch ? jsonMatch[0] : "";
  let original = meta;

  // For Telegram: keep t.me link as contact
  const originalContact = original.final_contact || original.sender_contact || null;

  let parsed = {};
  if (!jsonStr) return [{ json: { ...original, trash: true, category: 'trash', debug_raw: rawText } }];

  try { parsed = JSON.parse(jsonStr); }
  catch (ex) { return [{ json: { ...original, trash: true, category: 'trash', debug_error: ex.message } }]; }

  const isTrash = parsed.category === 'trash' || parsed.trash === true;

  return [{ json: { 
    ...original, 
    ...parsed, 
    contact: originalContact,
    final_contact: originalContact,
    sender_contact: originalContact,
    trash: isTrash 
  }}];
} catch(e) { return [{json:{ trash:true, category:'trash', debug_error: e.message }}]; }

const item = $json;

const text = String(item.text_es || "").toLowerCase();
const category = String(item.category || "").trim().toLowerCase();

const POSITIVE = ["apartamento","apartments","apartment","plaza","plazas","spot","spots","agency","agencia","club","booking","tour","girls","models","independent","independiente","trabajo","vacante","vacantes", "девочки", "девушки", "море", "европу", "модель", "встречи", "встреч", "кастинг", "эскорт", "заработок", "тусовки", "выезд", "апартаменты"];
const NEGATIVE = ["crypto","forex","casino","bank","teacher","course","insurance","loan","marketing","data entry","call center", "инди", "контент", "koнтент", "предоплаты", "онлифанс", "вирт", "кружочк"];

const positiveHits = POSITIVE.filter(k => text.includes(k)).length;
const negativeHits = NEGATIVE.filter(k => text.includes(k)).length;
const city = String(item.city || "").trim().toLowerCase();
const hasGoodCity = !!city && city !== "global" && city !== "unknown";

let reject = false, reason = null;

if (category === "trash") { reject = true; reason = "ai_trash"; }
else if (negativeHits >= 1 && positiveHits === 0) { reject = true; reason = "negative_signal"; }
else if (positiveHits === 0) { reject = true; reason = "no_positive_signal"; }
else if (!hasGoodCity && text.length < 180) { reject = true; reason = "weak_lead"; }

return { ...item, looksValuableFinal: !reject, reject_reason_final: reason };

const item = $json;
const textLength = (item.text_es || '').length;
const hasContact = !!item.contact;
const isPlaza = item.category === 'plaza';
let score = 0;

if (textLength > 200) score += 20;
if (textLength > 500) score += 20;
if (hasContact) score += 30;
if (isPlaza) score += 20;
if (!item.is_group_source) score += 10;
if (item.city && item.city !== 'Global') score += 10;

return { ...item, score };

const item = $input.first().json;

const TG_ES = '-5283488138';
const TG_EN = '-1003757267210';
